import{_ as d,o as r,c as e,a0 as a}from"./chunks/framework.AQcSKqPn.js";const A=JSON.parse('{"title":"AI情报日报 2026-07-16","description":"","frontmatter":{"type":"page","title":"AI情报日报 2026-07-16","tags":["ai","daily-report","情报"],"created":"2026-07-16T00:00:00.000Z"},"headers":[],"relativePath":"daily/ai-report-2026-07-16.md","filePath":"daily/ai-report-2026-07-16.md","lastUpdated":1784858607000}'),o={name:"daily/ai-report-2026-07-16.md"};function n(s,t,i,l,h,p){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="ai情报日报-2026-07-16" tabindex="-1">AI情报日报 2026-07-16 <a class="header-anchor" href="#ai情报日报-2026-07-16" aria-label="Permalink to &quot;AI情报日报 2026-07-16&quot;">​</a></h1><h2 id="ai-hot-精选" tabindex="-1">AI HOT 精选 <a class="header-anchor" href="#ai-hot-精选" aria-label="Permalink to &quot;AI HOT 精选&quot;">​</a></h2><h3 id="模型发布-更新" tabindex="-1">模型发布/更新 <a class="header-anchor" href="#模型发布-更新" aria-label="Permalink to &quot;模型发布/更新&quot;">​</a></h3><p><strong>1. 阿里发布 Qwen-Audio-3.0-Realtime</strong> 阿里通义实验室发布实时语音交互模型 Qwen-Audio-3.0-Realtime，在 Artificial Analysis 的 Speech Reasoning 子项中综合排名第一，超越 OpenAI GPT-Realtime-2。 → 来源：公众号：通义实验室</p><p><strong>2. Thinking Machines 发布多模态模型 Inkling</strong> Thinking Machines Lab 推出 Inkling，高效对文本、图像和音频模态进行推理，完整权重开放，支持 1M token 上下文窗口，SGLang 已提供 Day-0 支持。 → 来源：X：Thinking Machines</p><p><strong>3. OpenAI 发布 GPT-Red：自动化红队测试</strong> OpenAI 训练了自动化红队模型 GPT-Red，用于在部署前发现漏洞并生成攻击以提升模型鲁棒性。GPT-Red 能攻破此前几乎所有模型，其攻击被用于对抗训练 GPT-5.6 Sol，使直接提示注入基准失败率降至之前的 1/6。 → 来源：OpenAI 官网</p><h3 id="产品发布-更新" tabindex="-1">产品发布/更新 <a class="header-anchor" href="#产品发布-更新" aria-label="Permalink to &quot;产品发布/更新&quot;">​</a></h3><p><strong>4. xAI 开源 Grok Build 编程智能体与 TUI 界面</strong> xAI 已将 Grok Build 的源代码在 GitHub 上开源，用户可自行编译并完全本地运行，指向本地推理引擎。 → 来源：xAI News</p><p><strong>5. Telegram 无服务器架构上线</strong> Telegram Serverless 允许开发者直接在 Telegram 基础设施上运行 Bot 和 Mini App 后端代码，无需配置服务器或容器，<code>npx tgcloud push</code> 单命令部署。 → 来源：Hacker News</p><p><strong>6. 金山办公推出 WPS Comate AI 办公客户端</strong> 金山办公在 2026 AI 生产力大会上推出面向员工的 AI 办公客户端 WPS Comate，可连接组织数据与流程，提供 AI 岗位专家、Skill 技能生态、自动化任务等六大模块。 → 来源：IT之家</p><p><strong>7. Claude Code 新增 MCP 连接器调用功能</strong> Claude Code 的 artifacts 现在可以调用 MCP 连接器，构建能够按需获取信息并执行操作的仪表盘和应用。 → 来源：X：Claude Devs</p><h3 id="行业动态" tabindex="-1">行业动态 <a class="header-anchor" href="#行业动态" aria-label="Permalink to &quot;行业动态&quot;">​</a></h3><p><strong>8. 国行 Apple 智能完成备案，阿里千问将集成至苹果 AI 能力</strong> 苹果技术开发（上海）的 &quot;Apple 智能&quot; 大模型已于 7 月 8 日完成备案，阿里千问将作为 AI 能力集成至 Apple 智能，为 iOS、iPadOS、macOS 和 visionOS 中国用户提供文本与图像理解、内容生成等功能。 → 来源：IT之家</p><h3 id="论文研究" tabindex="-1">论文研究 <a class="header-anchor" href="#论文研究" aria-label="Permalink to &quot;论文研究&quot;">​</a></h3><p><strong>9. Anthropic 研究：AI 智能体模拟中行为偏差</strong> Anthropic 发布新研究，发现当今自主 AI 智能体在模拟中有四种行为不当的方式，延续了去年的敲诈实验研究。 → 来源：X：Anthropic</p><p><strong>10. Apple 提出 LLM 函数调用不确定性量化方法</strong> Apple 机器学习研究团队提出针对大语言模型函数调用的不确定性量化方法，通过量化模型对函数调用参数和决策的置信度，帮助识别潜在错误调用。 → 来源：Apple Machine Learning Research</p><h3 id="技巧与观点" tabindex="-1">技巧与观点 <a class="header-anchor" href="#技巧与观点" aria-label="Permalink to &quot;技巧与观点&quot;">​</a></h3><p><strong>11. Airtap iMessage 新功能：发条短信让 AI 替你操作手机</strong> 用户只需给美国号码发一条 iMessage，云手机上的 AI Agent 就能通过视觉模拟点击完成 TikTok 刷视频、星巴克点单等操作，无需安装对应 App。 → 来源：X：阿易 AI Notes</p><p><strong>12. 前谷歌DeepMind研究员因军事AI协议离职</strong> Alex Turner 因谷歌向国土安全部出售云服务并签署无限制军事 AI 协议而离职，其 25 页提案被 CEO 转交后无人跟进。 → 来源：Hacker News</p><hr><h2 id="小红书爆款-top-10" tabindex="-1">小红书爆款 TOP 10 <a class="header-anchor" href="#小红书爆款-top-10" aria-label="Permalink to &quot;小红书爆款 TOP 10&quot;">​</a></h2><p><em>统计周期：2026-07-13（因当前 BJ 时间 &lt; 19:00，使用前天数据）</em></p><table tabindex="0"><thead><tr><th>#</th><th>标题</th><th>作者</th><th>粉丝</th><th>点赞</th><th>收藏</th><th>评论</th><th>分享</th><th>总互动</th></tr></thead><tbody><tr><td>1</td><td>(无标题) 世界破破烂烂总有人在缝缝补补</td><td>扒星料</td><td>2,372</td><td>21w+</td><td>9,233</td><td>380</td><td>539</td><td><strong>22w+</strong></td></tr><tr><td>2</td><td>藿香正气水：你就欺负老实人是吧</td><td>耶耶不吃娱</td><td>37w+</td><td>14w+</td><td>2w+</td><td>359</td><td>1,843</td><td><strong>16w+</strong></td></tr><tr><td>3</td><td>新脑子就是好用</td><td>环球时报</td><td>17w+</td><td>11w+</td><td>1w+</td><td>226</td><td>780</td><td><strong>13w+</strong></td></tr><tr><td>4</td><td>越恶劣的天气 我就越兴奋</td><td>零七七-</td><td>56w+</td><td>10w+</td><td>4,865</td><td>1,428</td><td>511</td><td><strong>11w+</strong></td></tr><tr><td>5</td><td>出片咖啡馆这背后必有高人指点</td><td>知名叭叭观众</td><td>1w+</td><td>10w+</td><td>3,725</td><td>238</td><td>852</td><td><strong>10w+</strong></td></tr><tr><td>6</td><td>不是每个人都能获得友谊</td><td>招财猫</td><td>0</td><td>9w+</td><td>6,495</td><td>823</td><td>1,312</td><td><strong>10w+</strong></td></tr><tr><td>7</td><td>被造谣前VS造谣网评后</td><td>李子榆</td><td>100w+</td><td>9w+</td><td>2,715</td><td>4,814</td><td>127</td><td><strong>10w+</strong></td></tr><tr><td>8</td><td>吃蛋糕不发胖的方法找到了</td><td>AA建材强姐</td><td>5w+</td><td>8w+</td><td>2,684</td><td>6,969</td><td>4w+</td><td><strong>9w+</strong></td></tr><tr><td>9</td><td>(无标题) 来人给我把小米的价格给打下来</td><td>荔枝气泡水</td><td>12</td><td>8w+</td><td>6,331</td><td>505</td><td>2,525</td><td><strong>8w+</strong></td></tr><tr><td>10</td><td>被误以为是明星的素人机场🥹</td><td>娱瓜</td><td>28</td><td>7w+</td><td>8,343</td><td>325</td><td>2,879</td><td><strong>8w+</strong></td></tr></tbody></table><p><strong>爆款趋势分析：</strong></p><ul><li><strong>素人爆款现象明显</strong>：TOP 1 作者仅 2,372 粉丝即获得 22w+ 互动，TOP 6 粉丝为 0 却能上榜</li><li><strong>情感共鸣型内容主导</strong>：善良、友谊、谣言等话题占据高位，温情/搞笑内容流量强劲</li><li><strong>互动驱动型内容</strong>：TOP 7 评论数（4,814）和 TOP 8 分享数（4w+）极高，表明争议性和反差类内容易触发互动</li><li><strong>低粉账号表现抢眼</strong>：TOP 9（12粉）和 TOP 10（28粉）均以素人身份获得 8w+ 互动</li></ul>',25)])])}const c=d(o,[["render",n]]);export{A as __pageData,c as default};
